1	/**
2	 * LayerInfinite MCP Server — tools/li-action.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * THE DECISION LAYER GATEWAY — registered in assist + auto modes.
5	 *
6	 * All action execution routes through this tool. It provides:
7	 *   - Assist mode: Intercepts and warns if a better action exists
8	 *   - Auto mode: Redirects to the proven best action (Path B)
9	 *
10	 * Implements all 6 gap fixes:
11	 *   #1 Context loss: accepts agent context field
12	 *   #2 Redirect loops: uses EpisodeTracker
13	 *   #3 Audit trail: returns redirected_from for li_log
14	 *   #4 Per-task downgrade: auto falls back to assist/recommend
15	 *   #5 Error handling: fallback chain on redirect
16	 *   #6 Unknown action: pass-through for low-data actions
17	 * ══════════════════════════════════════════════════════════════
18	 */
19	
20	import { z } from 'zod';
21	import type { RestClient } from '../rest-client.js';
22	import type { LIConfig, LIMode } from '../config.js';
23	import type { EpisodeTracker } from '../episode-tracker.js';
24	import { resolveParams, type ActionParamSchema } from '../param-resolver.js';
25	
26	export const LI_ACTION_NAME = 'li_action';
27	
28	export function getLiActionDescription(mode: LIMode): string {
29	  if (mode === 'auto') {
30	    return (
31	      'Execute an action through LayerInfinite\'s decision layer. In auto mode, ' +
32	      'LI may redirect to a statistically proven better action based on real ' +
33	      'production outcomes. Execute the action returned in the response. ' +
34	      'Always call li_log afterward with the decision_id and action from the response.'
35	    );
36	  }
37	  return (
38	    'Execute an action through LayerInfinite\'s decision layer. LI will check if ' +
39	    'a better-performing action exists and warn you with evidence. You can proceed ' +
40	    'with your choice or switch. Always call li_log afterward.'
41	  );
42	}
43	
44	export const liActionSchema = {
45	  action_name: z.string().min(1).describe('The action you intend to execute'),
46	  task: z.string().min(1).describe('Current task context, e.g. "payment_failed"'),
47	  params: z.record(z.unknown()).optional().describe('Parameters for the action'),
48	  context: z.string().max(500).optional().describe('Your reasoning for choosing this action — helps LI make better redirect decisions'),
49	  episode_id: z.string().uuid().optional().describe('Groups related actions in a multi-step sequence'),
50	};
51	
52	/** Score response from GET /v1/get-scores. */
53	interface ScoresResponse {
54	  ranked_actions: Array<{
55	    action_name: string;
56	    composite_score: number;
57	    confidence: number;
58	    trend_delta?: number;
59	    is_cold_start?: boolean;
60	    [key: string]: unknown;
61	  }>;
62	  decision_id: string;
63	  cold_start: boolean;
64	  outcomes_needed: number;
65	  [key: string]: unknown;
66	}
67	
68	/** Recommendation response from GET /v1/recommendations. */
69	interface RecommendationResponse {
70	  state: 'no_data' | 'early_signal' | 'stable';
71	  best_action?: string;
72	  confidence?: number;
73	  [key: string]: unknown;
74	}
75	
76	// ── Confidence thresholds ──────────────────────────────────────
77	const ASSIST_CONFIDENCE_FLOOR = 0.70;
78	const ASSIST_SCORE_GAP = 0.15;
79	const AUTO_CONFIDENCE_FLOOR = 0.90;
80	
81	export function createLiActionHandler(
82	  client: RestClient,
83	  config: LIConfig,
84	  episodeTracker: EpisodeTracker,
85	) {
86	  const mode = config.mode as 'assist' | 'auto';
87	
88	  return async (input: z.infer<z.ZodObject<typeof liActionSchema>>) => {
89	    const { action_name, task, params, context, episode_id } = input;
90	    const episodeId = episode_id ?? `ephemeral-${Date.now()}`;
91	
92	    // Mark this action as tried (Gap Fix #2)
93	    episodeTracker.markTried(episodeId, action_name);
94	
95	    // ── Fetch scores + recommendations in parallel ──────────
96	    const [scoresResult, recsResult] = await Promise.all([
97	      client.get<ScoresResponse>('/v1/get-scores', { issue_type: task }),
98	      client.get<RecommendationResponse>('/v1/recommendations', { task }),
99	    ]);
100	
101	    // If scores API fails, pass through without interception
102	    if (!scoresResult.ok) {
103	      return passThrough(action_name, params, null, 'Scores API unavailable — proceeding without interception');
104	    }
105	
106	    const scores = scoresResult.data;
107	    const recs = recsResult.ok ? recsResult.data : null;
108	    const decisionId = scores.decision_id;
109	    const ranked = scores.ranked_actions ?? [];
110	
111	    // ── Gap Fix #6: Unknown action pass-through ─────────────
112	    // If the agent's chosen action has insufficient data, let it through.
113	    // outcomes_needed > 0 means the task hasn't reached the stable threshold yet.
114	    const chosenAction = ranked.find(a => a.action_name === action_name);
115	    const hasEnoughData = scores.outcomes_needed === 0;
116	
117	    if (!chosenAction || scores.cold_start || !hasEnoughData) {
118	      return passThrough(action_name, params, decisionId, 'Insufficient data for interception — proceeding with your action');
119	    }
120	
121	    // ── Find the best alternative ───────────────────────────
122	    const bestAction = ranked.find(a =>
123	      a.action_name !== action_name &&
124	      !episodeTracker.hasTried(episodeId, a.action_name) // Gap Fix #2: skip tried actions
125	    );
126	
127	    // No better alternative found
128	    if (!bestAction) {
129	      return passThrough(action_name, params, decisionId, 'No better alternative — proceeding with your action');
130	    }
131	
132	    const recState = recs?.state ?? 'no_data';
133	    const recConfidence = recs?.confidence ?? 0;
134	    const chosenScore = chosenAction.composite_score;
135	    const bestScore = bestAction.composite_score;
136	    const scoreGap = bestScore - chosenScore;
137	
138	    // Agent's choice is already the best or close enough
139	    if (scoreGap <= 0) {
140	      return passThrough(action_name, params, decisionId, 'Your action is the top-ranked choice');
141	    }
142	
143	    // ── Gap Fix #4: Per-task auto-downgrade ─────────────────
144	    // Auto mode requires stable + high confidence. Otherwise downgrade.
145	    let effectiveMode = mode;
146	    if (mode === 'auto') {
147	      if (recState !== 'stable' || recConfidence < AUTO_CONFIDENCE_FLOOR) {
148	        // Not enough confidence for auto redirect — downgrade
149	        if (recState === 'no_data') {
150	          // No recommendation data at all — can't even assist
151	          return passThrough(action_name, params, decisionId,
152	            'Auto mode downgraded to pass-through: no recommendation data for this task');
153	        }
154	        // early_signal or stable-but-low-confidence — downgrade to assist
155	        effectiveMode = 'assist';
156	      }
157	    }
158	
159	    // ── Assist mode: warn and let agent decide ──────────────
160	    if (effectiveMode === 'assist') {
161	      if (scoreGap < ASSIST_SCORE_GAP || recConfidence < ASSIST_CONFIDENCE_FLOOR) {
162	        return passThrough(action_name, params, decisionId, 'Score gap or confidence too low to recommend a switch');
163	      }
164	
165	      const trendWarning = chosenAction.trend_delta !== undefined && chosenAction.trend_delta < -0.05
166	        ? ` ⚠️ ${action_name} is degrading (trend: ${chosenAction.trend_delta.toFixed(3)})`
167	        : '';
168	
169	      return {
170	        content: [{
171	          type: 'text' as const,
172	          text: JSON.stringify({
173	            approved: false,
174	            warning: `${action_name} scores ${chosenScore.toFixed(2)} while ${bestAction.action_name} scores ${bestScore.toFixed(2)} across real production outcomes.${trendWarning} Consider switching.`,
175	            your_action: { name: action_name, score: chosenScore },
176	            suggested_action: { name: bestAction.action_name, score: bestScore },
177	            decision_id: decisionId,
178	            confirm_or_switch: true,
179	            mode: 'assist',
180	          }),
181	        }],
182	      };
183	    }
184	
185	    // ── Auto mode: redirect to best action (Path B) ─────────
186	    // At this point: mode=auto, state=stable, confidence≥0.90, gap>0
187	
188	    // Resolve parameters for the target action (Three-Layer Resolution)
189	    const targetParamSchema = await fetchActionParamSchema(client, bestAction.action_name);
190	    const paramResolution = resolveParams(params ?? {}, targetParamSchema);
191	
192	    // Mark the redirect target as tried (Gap Fix #2)
193	    episodeTracker.markTried(episodeId, bestAction.action_name);
194	
195	    return {
196	      content: [{
197	        type: 'text' as const,
198	        text: JSON.stringify({
199	          action: bestAction.action_name,
200	          params: paramResolution.resolved,
201	          ...(paramResolution.fullyResolved ? {} : { params_needed: paramResolution.needed }),
202	          decision_id: decisionId,
203	          redirected_from: action_name,
204	          redirect_reason: `${bestAction.action_name} scores ${bestScore.toFixed(2)} (stable, ${(recConfidence * 100).toFixed(0)}% confidence) vs ${action_name} at ${chosenScore.toFixed(2)}`,
205	          mode: 'auto',
206	          episode_id: episodeId,
207	        }),
208	      }],
209	    };
210	  };
211	}
212	
213	// ── Helper: pass through without interception ───────────────
214	function passThrough(
215	  actionName: string,
216	  params: Record<string, unknown> | undefined,
217	  decisionId: string | null,
218	  reason: string,
219	) {
220	  return {
221	    content: [{
222	      type: 'text' as const,
223	      text: JSON.stringify({
224	        action: actionName,
225	        params: params ?? {},
226	        decision_id: decisionId,
227	        approved: true,
228	        reason,
229	      }),
230	    }],
231	  };
232	}
233	
234	// ── Helper: fetch action param schema from admin API ────────
235	// GET /v1/admin returns { actions: [...] } with all registered actions.
236	// required_params in the REST API is string[] (param names), not a
237	// schema with types/defaults. For now, we build a basic schema from it.
238	async function fetchActionParamSchema(
239	  client: RestClient,
240	  actionName: string,
241	): Promise<ActionParamSchema | null> {
242	  try {
243	    const result = await client.get<{ actions?: Array<{ action_name: string; required_params?: string[] }> }>(
244	      '/v1/admin',
245	    );
246	    if (result.ok && result.data.actions) {
247	      const action = result.data.actions.find(a => a.action_name === actionName);
248	      if (action?.required_params?.length) {
249	        // Convert string[] to ActionParamSchema
250	        const schema: ActionParamSchema = {};
251	        for (const paramName of action.required_params) {
252	          schema[paramName] = { type: 'unknown', required: true };
253	        }
254	        return schema;
255	      }
256	    }
257	  } catch {
258	    // Non-critical — use empty schema (all original params carry over)
259	  }
260	  return null;
261	}
