1	/**
2	 * LayerInfinite MCP Server — resources/task-intelligence.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * MCP Resource: layerinfinite://tasks/{task_name}
5	 *
6	 * THE DECISION LAYER — always active regardless of mode.
7	 * Injects scored action intelligence into the agent's context
8	 * BEFORE the agent reasons about which action to take.
9	 *
10	 * This is how LI works like a memory layer — the agent reads this
11	 * resource and reasons WITH the data, not against it.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { RestClient } from '../rest-client.js';
16	import type { LIConfig } from '../config.js';
17	
18	/** Score response from GET /v1/get-scores. */
19	interface ScoresResponse {
20	  ranked_actions: Array<{
21	    action_name: string;
22	    composite_score: number;
23	    confidence: number;
24	    trend_delta?: number;
25	    is_cold_start?: boolean;
26	  }>;
27	  cold_start: boolean;
28	  outcomes_needed: number;
29	  decision_id: string;
30	  [key: string]: unknown;
31	}
32	
33	/** Recommendation response from GET /v1/recommendations. */
34	interface RecommendationResponse {
35	  state: 'no_data' | 'early_signal' | 'stable';
36	  best_action?: string;
37	  confidence?: number;
38	  improvement?: number;
39	  [key: string]: unknown;
40	}
41	
42	export const TASK_RESOURCE_TEMPLATE = 'layerinfinite://tasks/{task_name}';
43	
44	/**
45	 * Creates the resource read handler for layerinfinite://tasks/{task_name}.
46	 * Returns formatted intelligence data that becomes part of the agent's context.
47	 */
48	export function createTaskIntelligenceReader(client: RestClient, config: LIConfig) {
49	  return async (uri: URL, variables: Record<string, string | string[]>) => {
50	    const rawTaskName = variables.task_name;
51	    const taskName = (Array.isArray(rawTaskName) ? rawTaskName[0] : rawTaskName) ?? uri.pathname.split('/').pop() ?? '';
52	
53	    if (!taskName) {
54	      return {
55	        contents: [{
56	          uri: uri.toString(),
57	          mimeType: 'application/json',
58	          text: JSON.stringify({ error: 'Task name is required' }),
59	        }],
60	      };
61	    }
62	
63	    // Fetch scores + recommendations in parallel
64	    const [scoresResult, recsResult] = await Promise.all([
65	      client.get<ScoresResponse>('/v1/get-scores', { issue_type: taskName }),
66	      client.get<RecommendationResponse>('/v1/recommendations', { task: taskName }),
67	    ]);
68	
69	    if (!scoresResult.ok) {
70	      return {
71	        contents: [{
72	          uri: uri.toString(),
73	          mimeType: 'application/json',
74	          text: JSON.stringify({
75	            task: taskName,
76	            status: 'unavailable',
77	            message: 'Could not fetch intelligence — API may be unreachable',
78	          }),
79	        }],
80	      };
81	    }
82	
83	    const scores = scoresResult.data;
84	    const recs = recsResult.ok ? recsResult.data : null;
85	
86	    // Format the intelligence data
87	    const intelligence: Record<string, unknown> = {
88	      task: taskName,
89	      cold_start: scores.cold_start,
90	      outcomes_needed: scores.outcomes_needed,
91	      decision_id: scores.decision_id,
92	    };
93	
94	    if (scores.cold_start || !scores.ranked_actions?.length) {
95	      intelligence.status = 'no_data';
96	      intelligence.message = `No outcome data for "${taskName}" yet. Execute actions and log via li_log to begin learning.`;
97	    } else {
98	      intelligence.status = recs?.state ?? 'early_signal';
99	      intelligence.ranked_actions = scores.ranked_actions.map(a => ({
100	        action: a.action_name,
101	        score: a.composite_score,
102	        confidence: a.confidence,
103	        trend: a.trend_delta ?? 0,
104	      }));
105	
106	      if (recs?.best_action) {
107	        intelligence.recommendation = {
108	          best_action: recs.best_action,
109	          confidence: recs.confidence,
110	          improvement: recs.improvement,
111	          state: recs.state,
112	        };
113	      }
114	
115	      // Mode-specific guidance
116	      const mode = config.mode;
117	      if (mode === 'auto' && recs?.state === 'stable' && (recs?.confidence ?? 0) >= 0.90) {
118	        intelligence.guidance = `DECISION LAYER: ${recs!.best_action} is the statistically proven best action (${((recs!.confidence ?? 0) * 100).toFixed(0)}% confidence, stable). Route through li_action to execute.`;
119	      } else if (mode === 'assist') {
120	        intelligence.guidance = `LI suggests ${recs?.best_action ?? scores.ranked_actions[0]?.action_name}. Route through li_action for interception check.`;
121	      } else {
122	        intelligence.guidance = `Data available. ${scores.ranked_actions[0]?.action_name} ranks highest at ${scores.ranked_actions[0]?.composite_score.toFixed(2)}.`;
123	      }
124	    }
125	
126	    return {
127	      contents: [{
128	        uri: uri.toString(),
129	        mimeType: 'application/json',
130	        text: JSON.stringify(intelligence),
131	      }],
132	    };
133	  };
134	}
