1	/**
2	 * Integration tests for li-action.ts — Decision Layer Gateway
3	 *
4	 * Uses a mock RestClient to test all decision paths:
5	 *   - Pass-through on cold start
6	 *   - Pass-through on insufficient data
7	 *   - Assist mode: warn when better action exists
8	 *   - Assist mode: pass-through when gap too small
9	 *   - Auto mode: redirect to best action (Path B)
10	 *   - Auto mode: downgrade to assist on low confidence
11	 *   - Auto mode: pass-through on no_data
12	 *   - Loop prevention via EpisodeTracker
13	 */
14	import { describe, it, expect, beforeEach } from 'vitest';
15	import { createLiActionHandler } from '../src/tools/li-action.js';
16	import { EpisodeTracker } from '../src/episode-tracker.js';
17	import type { LIConfig } from '../src/config.js';
18	import type { LIResult } from '../src/rest-client.js';
19	
20	// ── Mock RestClient ─────────────────────────────────────────
21	function createMockClient(options: {
22	  scores?: Record<string, unknown>;
23	  scoresError?: boolean;
24	  recommendations?: Record<string, unknown>;
25	  recsError?: boolean;
26	  adminActions?: unknown[];
27	}) {
28	  return {
29	    get: async <T>(path: string): Promise<LIResult<T>> => {
30	      if (path.startsWith('/v1/get-scores')) {
31	        if (options.scoresError) {
32	          return { ok: false, status: 503, error: { error: 'unavailable', code: 'SERVICE_UNAVAILABLE' } } as LIResult<T>;
33	        }
34	        return { ok: true, status: 200, data: options.scores as T } as LIResult<T>;
35	      }
36	      if (path.startsWith('/v1/recommendations')) {
37	        if (options.recsError) {
38	          return { ok: false, status: 503, error: { error: 'unavailable', code: 'SERVICE_UNAVAILABLE' } } as LIResult<T>;
39	        }
40	        return { ok: true, status: 200, data: options.recommendations as T } as LIResult<T>;
41	      }
42	      if (path.startsWith('/v1/admin')) {
43	        return { ok: true, status: 200, data: { actions: options.adminActions ?? [] } as T } as LIResult<T>;
44	      }
45	      return { ok: false, status: 404, error: { error: 'Not found', code: 'NOT_FOUND' } } as LIResult<T>;
46	    },
47	    post: async <T>(): Promise<LIResult<T>> => {
48	      return { ok: true, status: 200, data: {} as T } as LIResult<T>;
49	    },
50	    put: async <T>(): Promise<LIResult<T>> => {
51	      return { ok: true, status: 200, data: {} as T } as LIResult<T>;
52	    },
53	  };
54	}
55	
56	function makeConfig(mode: 'assist' | 'auto'): LIConfig {
57	  return Object.freeze({
58	    apiKey: 'test-key',
59	    baseUrl: 'https://test.layerinfinite.me',
60	    mode,
61	    adminKey: null,
62	  });
63	}
64	
65	function parseResponse(result: { content: Array<{ text: string }> }): Record<string, unknown> {
66	  return JSON.parse(result.content[0].text);
67	}
68	
69	// ── Reusable score fixtures ─────────────────────────────────
70	const stableScores = {
71	  ranked_actions: [
72	    { action_name: 'switch_provider', composite_score: 0.85, confidence: 0.92 },
73	    { action_name: 'retry_payment', composite_score: 0.60, confidence: 0.88 },
74	    { action_name: 'escalate_to_human', composite_score: 0.40, confidence: 0.95 },
75	  ],
