4	import { describe, it, expect } from 'vitest';
5	import { resolveParams, type ActionParamSchema } from '../src/param-resolver.js';
6	
7	describe('resolveParams', () => {
8	  // ── Null / empty schema ───────────────────────────────────
9	  it('returns all original params when schema is null', () => {
10	    const result = resolveParams({ a: 1, b: 'two' }, null);
11	    expect(result.fullyResolved).toBe(true);
12	    expect(result.resolved).toEqual({ a: 1, b: 'two' });
13	    expect(Object.keys(result.needed)).toHaveLength(0);
14	  });
15	
16	  it('returns all original params when schema is empty', () => {
17	    const result = resolveParams({ x: 'val' }, {});
18	    expect(result.fullyResolved).toBe(true);
19	    expect(result.resolved).toEqual({ x: 'val' });
20	  });
21	
22	  // ── Layer 1: Shared params carry over ─────────────────────
23	  it('Layer 1: carries over matching param names', () => {
24	    const schema: ActionParamSchema = {
25	      transaction_id: { type: 'string', required: true },
26	      amount: { type: 'number', required: true },
27	    };
28	    const result = resolveParams({ transaction_id: 'tx-123', amount: 50 }, schema);
29	    expect(result.fullyResolved).toBe(true);
30	    expect(result.resolved).toEqual({ transaction_id: 'tx-123', amount: 50 });
31	  });
32	
33	  // ── Layer 2: Defaults fill gaps ───────────────────────────
34	  it('Layer 2: fills from defaults when original param missing', () => {
35	    const schema: ActionParamSchema = {
36	      transaction_id: { type: 'string', required: true },
37	      provider_name: { type: 'string', required: true, default: 'stripe' },
38	    };
39	    const result = resolveParams({ transaction_id: 'tx-123' }, schema);
40	    expect(result.fullyResolved).toBe(true);
41	    expect(result.resolved).toEqual({ transaction_id: 'tx-123', provider_name: 'stripe' });
42	  });
43	
44	  // ── Layer 3: Missing required params → agent must fill ────
45	  it('Layer 3: marks unresolvable required params as needed', () => {
46	    const schema: ActionParamSchema = {
47	      transaction_id: { type: 'string', required: true },
48	      fallback_config: { type: 'object', required: true },
49	    };
50	    const result = resolveParams({ transaction_id: 'tx-123' }, schema);
51	    expect(result.fullyResolved).toBe(false);
52	    expect(result.resolved).toEqual({ transaction_id: 'tx-123' });
53	    expect(result.needed).toHaveProperty('fallback_config');
54	  });
55	
56	  // ── Optional params don't block resolution ────────────────
57	  it('optional params with no match are not marked as needed', () => {
58	    const schema: ActionParamSchema = {
59	      transaction_id: { type: 'string', required: true },
60	      metadata: { type: 'object', required: false },
61	    };
62	    const result = resolveParams({ transaction_id: 'tx-123' }, schema);
63	    expect(result.fullyResolved).toBe(true);
64	    expect(result.resolved).toEqual({ transaction_id: 'tx-123' });
65	    expect(Object.keys(result.needed)).toHaveLength(0);
66	  });
67	
68	  // ── Full 3-layer scenario ─────────────────────────────────
69	  it('all three layers in one redirect scenario', () => {
70	    // retry_payment → switch_provider
71	    const originalParams = {
72	      transaction_id: 'tx-999',
73	      amount: 100,
74	      retry_count: 3, // not needed by target
75	    };
76	
77	    const targetSchema: ActionParamSchema = {
78	      transaction_id: { type: 'string', required: true },  // Layer 1: match
79	      amount: { type: 'number', required: true },           // Layer 1: match
80	      provider_name: { type: 'string', required: true, default: 'stripe_backup' }, // Layer 2: default
81	      fallback_config: { type: 'object', required: true },  // Layer 3: agent must fill
82	    };
83	
84	    const result = resolveParams(originalParams, targetSchema);
85	    expect(result.fullyResolved).toBe(false);
86	    expect(result.resolved).toEqual({
87	      transaction_id: 'tx-999',
88	      amount: 100,
89	      provider_name: 'stripe_backup',
90	    });
91	    expect(result.needed).toHaveProperty('fallback_config');
92	    expect(Object.keys(result.needed)).toHaveLength(1);
