5	 */
6	
7	import { describe, it, expect } from 'vitest';
8	
9	// ── Test the pure logic: action validation rules ──────────────
10	
11	describe('Hallucination Prevention — Action Validation', () => {
12	
13	    // Simulated action registry (mirrors dim_actions seed data)
14	    const REGISTERED_ACTIONS = [
15	        'retry_transaction', 'restart_service', 'update_app',
16	        'escalate_human', 'switch_provider', 'send_notification',
17	        'clear_cache', 'verify_credentials',
18	    ];
19	
20	    const FAKE_ACTIONS = [
21	        'delete_database',
22	        'hack_server',
23	        'deploy_to_mars',
24	        'restart_universe',
25	        '',
26	        'a'.repeat(256),
27	    ];
28	
29	    it('registered actions are recognized', () => {
30	        for (const action of REGISTERED_ACTIONS) {
31	            expect(REGISTERED_ACTIONS.includes(action)).toBe(true);
32	        }
33	    });
34	
35	    it('fake actions are NOT in the registry', () => {
36	        for (const fake of FAKE_ACTIONS) {
37	            expect(REGISTERED_ACTIONS.includes(fake)).toBe(false);
38	        }
39	    });
40	
41	    it('action names are case-sensitive', () => {
42	        expect(REGISTERED_ACTIONS.includes('Retry_Transaction')).toBe(false);
43	        expect(REGISTERED_ACTIONS.includes('RETRY_TRANSACTION')).toBe(false);
44	        expect(REGISTERED_ACTIONS.includes('retry_transaction')).toBe(true);
45	    });
46	
47	    it('empty string is rejected', () => {
48	        expect(REGISTERED_ACTIONS.includes('')).toBe(false);
49	    });
50	
51	    it('action name max length is enforced', () => {
52	        const tooLong = 'a'.repeat(256);
53	        expect(tooLong.length).toBeGreaterThan(255);
54	        expect(REGISTERED_ACTIONS.includes(tooLong)).toBe(false);
55	    });
56	});
57	
58	describe('Hallucination Prevention — Required Params Validation', () => {
59	
60	    function validateParams(
61	        requiredKeys: string[],
62	        providedParams?: Record<string, unknown>
63	    ): { valid: boolean; missing: string[] } {
64	        if (requiredKeys.length === 0) return { valid: true, missing: [] };
65	
66	        if (!providedParams) {
67	            return { valid: false, missing: requiredKeys };
68	        }
69	
70	        const missing = requiredKeys.filter(k => !(k in providedParams));
71	        return { valid: missing.length === 0, missing };
72	    }
73	
74	    it('no required params → always valid', () => {
75	        expect(validateParams([], undefined).valid).toBe(true);
76	        expect(validateParams([], {}).valid).toBe(true);
77	        expect(validateParams([], { foo: 'bar' }).valid).toBe(true);
78	    });
79	
80	    it('required params present → valid', () => {
81	        expect(validateParams(['amount'], { amount: 100 }).valid).toBe(true);
82	        expect(validateParams(['a', 'b'], { a: 1, b: 2, c: 3 }).valid).toBe(true);
83	    });
84	
85	    it('required params missing → invalid + lists missing', () => {
86	        const result = validateParams(['amount', 'currency'], { amount: 100 });
87	        expect(result.valid).toBe(false);
88	        expect(result.missing).toEqual(['currency']);
89	    });
90	
91	    it('no params provided but required → invalid', () => {
92	        const result = validateParams(['amount'], undefined);
93	        expect(result.valid).toBe(false);
94	        expect(result.missing).toEqual(['amount']);
95	    });
96	
97	    it('empty params object but required → invalid', () => {
98	        const result = validateParams(['token'], {});
99	        expect(result.valid).toBe(false);
100	        expect(result.missing).toEqual(['token']);
101	    });
102	});
103	
104	describe('Hallucination Prevention — Error Messages', () => {
105	
106	    function formatBlockMessage(actionName: string): string {
107	        return `HALLUCINATION BLOCKED: action "${actionName}" is not registered in dim_actions. ` +
108	            `Only registered actions can be logged. Register via POST /v1/admin/register-action.`;
109	    }
110	
111	    it('error message includes action name', () => {
112	        const msg = formatBlockMessage('fake_action');
113	        expect(msg).toContain('fake_action');
114	        expect(msg).toContain('HALLUCINATION BLOCKED');
115	        expect(msg).toContain('dim_actions');
116	    });
117	
118	    it('error message includes registration hint', () => {
119	        const msg = formatBlockMessage('unknown');
120	        expect(msg).toContain('/v1/admin/register-action');
121	    });
122	});
