10	// ═══════════════════════════════════════════════════════════════
11	// GAP 1 — LATENCY SPIKE DETECTION
12	// ═══════════════════════════════════════════════════════════════
13	
14	describe('Gap 1 — Latency Spike Detection', () => {
15	    const LATENCY_SPIKE_THRESHOLD = 3.0;
16	
17	    function shouldAlert(spike: {
18	        latency_spike_ratio: number | null;
19	        total_attempts: number;
20	    }): boolean {
21	        return (
22	            spike.latency_spike_ratio !== null &&
23	            spike.latency_spike_ratio >= LATENCY_SPIKE_THRESHOLD &&
24	            spike.total_attempts >= 10
25	        );
26	    }
27	
28	    function getSeverity(ratio: number): 'critical' | 'warning' {
29	        return ratio >= 5.0 ? 'critical' : 'warning';
30	    }
31	
32	    it('latency_spike_ratio = 3.5 → alert emitted', () => {
33	        expect(shouldAlert({ latency_spike_ratio: 3.5, total_attempts: 50 })).toBe(true);
34	    });
35	
36	    it('latency_spike_ratio = 2.9 → no alert', () => {
37	        expect(shouldAlert({ latency_spike_ratio: 2.9, total_attempts: 50 })).toBe(false);
38	    });
39	
40	    it('no baseline data → spike_ratio is null → no alert', () => {
41	        expect(shouldAlert({ latency_spike_ratio: null, total_attempts: 100 })).toBe(false);
42	    });
43	
44	    it('spike_ratio = 3.0 but only 5 attempts → no alert (below min sample)', () => {
45	        expect(shouldAlert({ latency_spike_ratio: 3.0, total_attempts: 5 })).toBe(false);
46	    });
47	
48	    it('spike_ratio exactly 3.0 → alert emitted (threshold inclusive)', () => {
49	        expect(shouldAlert({ latency_spike_ratio: 3.0, total_attempts: 10 })).toBe(true);
50	    });
51	
52	    it('spike_ratio >= 5.0 → severity is critical', () => {
53	        expect(getSeverity(5.0)).toBe('critical');
54	        expect(getSeverity(7.2)).toBe('critical');
55	    });
56	
57	    it('spike_ratio < 5.0 → severity is warning', () => {
58	        expect(getSeverity(3.0)).toBe('warning');
59	        expect(getSeverity(4.9)).toBe('warning');
60	    });
61	
62	    it('latency spike deduped within 24h', () => {
63	        const now = Date.now();
64	        const twentyThreeHoursAgo = new Date(now - 23 * 60 * 60 * 1000);
65	        const twentyFiveHoursAgo = new Date(now - 25 * 60 * 60 * 1000);
66	        const dedupWindow = new Date(now - 24 * 60 * 60 * 1000);
67	
68	        expect(twentyThreeHoursAgo.getTime()).toBeGreaterThan(dedupWindow.getTime()); // within window → dedup
69	        expect(twentyFiveHoursAgo.getTime()).toBeLessThan(dedupWindow.getTime()); // outside window → new alert
70	    });
71	});
