1	/**
2	 * Layerinfinite — Phase 6 Unit Tests: Trust Score System
3	 * ══════════════════════════════════════════════════════════════
4	 * Tests the trust update rules, decay math, status thresholds,
5	 * and reinstatement logic.
6	 *
7	 * Run: npx vitest run tests/layer6/trust.test.ts
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { describe, it, expect } from 'vitest';
12	
13	// ── Trust update rules (mirrors log-outcome.ts + trust-updater) ──
14	
15	interface TrustState {
16	    trust_score: number;
17	    consecutive_failures: number;
18	    total_decisions: number;
19	    correct_decisions: number;
20	    trust_status: string;
21	}
22	
23	function applyOutcome(state: TrustState, success: boolean): TrustState {
24	    let newScore: number;
25	    let newFailures: number;
26	    let newCorrect = state.correct_decisions;
27	
28	    if (success) {
29	        newFailures = 0;
30	        newCorrect += 1;
31	        newScore = Math.min(state.trust_score * 1.03, 1.0);
32	    } else {
33	        newFailures = state.consecutive_failures + 1;
34	        newScore = state.trust_score * Math.pow(0.9, newFailures);
35	    }
36	
37	    let newStatus: string;
38	    if (newScore < 0.3 || newFailures >= 5) {
39	        newStatus = 'suspended';
40	    } else if (newScore < 0.6) {
41	        newStatus = 'probation';
42	    } else {
43	        newStatus = 'trusted';
44	    }
45	
46	    return {
47	        trust_score: newScore,
48	        consecutive_failures: newFailures,
49	        total_decisions: state.total_decisions + 1,
50	        correct_decisions: newCorrect,
51	        trust_status: newStatus,
52	    };
53	}
54	
55	function reinstate(): Partial<TrustState> {
56	    return {
57	        trust_score: 0.4,
58	        trust_status: 'probation',
59	        consecutive_failures: 0,
60	    };
61	}
62	
63	// ══════════════════════════════════════════════════════════════
64	// Tests
65	// ══════════════════════════════════════════════════════════════
66	
67	describe('Phase 6 — Trust Score System', () => {
68	
69	    // ── Test 1: Trust decays correctly under 5 consecutive failures ──
70	    it('5 consecutive failures suspends the agent', () => {
71	        let state: TrustState = {
72	            trust_score: 0.7,
73	            consecutive_failures: 0,
74	            total_decisions: 10,
75	            correct_decisions: 8,
76	            trust_status: 'trusted',
77	        };
78	
79	        // Apply 5 failures
80	        for (let i = 0; i < 5; i++) {
81	            state = applyOutcome(state, false);
82	        }
83	
84	        expect(state.trust_status).toBe('suspended');
85	        expect(state.consecutive_failures).toBe(5);
86	        expect(state.total_decisions).toBe(15);
87	
88	        // Score should have decayed: 0.7 * 0.9^1 * 0.9^2 * 0.9^3 * 0.9^4 * 0.9^5
89	        // But it's cumulative: after each step failures increment
90	        // Failure 1: 0.7 * 0.9^1 = 0.63
91	        // Failure 2: 0.63 * 0.9^2 = 0.5103
92	        // Failure 3: 0.5103 * 0.9^3 = 0.37176
93	        // Failure 4: 0.37176 * 0.9^4 = 0.24414
94	        // Failure 5: 0.24414 * 0.9^5 = 0.14441
95	        expect(state.trust_score).toBeLessThan(0.3);
96	    });
97	
98	    // ── Test 2: Trust recovers slowly — 3 successes from 0.5 stays in probation ──
99	    it('3 successes from 0.5 stays in probation (not yet 0.6)', () => {
100	        let state: TrustState = {
101	            trust_score: 0.5,
102	            consecutive_failures: 0,
103	            total_decisions: 20,
104	            correct_decisions: 14,
105	            trust_status: 'probation',
106	        };
107	
108	        // Apply 3 successes: 0.5 * 1.03^3 ≈ 0.5464
109	        state = applyOutcome(state, true);
110	        state = applyOutcome(state, true);
111	        state = applyOutcome(state, true);
112	
113	        const expectedScore = 0.5 * Math.pow(1.03, 3);  // ≈ 0.5464
114	        expect(state.trust_score).toBeCloseTo(expectedScore, 4);
115	        expect(state.trust_score).toBeLessThan(0.6);
116	        expect(state.trust_status).toBe('probation');
117	        expect(state.consecutive_failures).toBe(0);
118	        expect(state.correct_decisions).toBe(17);
119	    });
120	
121	    // ── Test 3: Human reinstatement sets correct values ──
122	    it('reinstatement sets trust_score=0.4, status=probation, failures=0', () => {
123	        const reinstated = reinstate();
124	
125	        expect(reinstated.trust_score).toBe(0.4);
126	        expect(reinstated.trust_status).toBe('probation');
127	        expect(reinstated.consecutive_failures).toBe(0);
128	    });
129	
130	    // ── Test 4: Success resets consecutive_failures to 0 ──
131	    it('success resets consecutive_failures to zero', () => {
132	        let state: TrustState = {
133	            trust_score: 0.6,
134	            consecutive_failures: 3,
135	            total_decisions: 15,
136	            correct_decisions: 10,
137	            trust_status: 'trusted',
138	        };
139	
140	        state = applyOutcome(state, true);
141	
142	        expect(state.consecutive_failures).toBe(0);
143	        expect(state.trust_score).toBe(Math.min(0.6 * 1.03, 1.0));
144	        expect(state.correct_decisions).toBe(11);
145	    });
146	
147	    // ── Test 5: Score capped at 1.0 ──
148	    it('trust score is capped at 1.0 on success', () => {
149	        let state: TrustState = {
150	            trust_score: 0.99,
151	            consecutive_failures: 0,
152	            total_decisions: 100,
153	            correct_decisions: 95,
154	            trust_status: 'trusted',
155	        };
156	
157	        state = applyOutcome(state, true);
158	
159	        expect(state.trust_score).toBeLessThanOrEqual(1.0);
160	        expect(state.trust_status).toBe('trusted');
161	    });
162	
163	    // ── Test 6: Threshold boundaries ──
164	    it('score 0.6 exactly is trusted, 0.599 is probation, 0.299 is suspended', () => {
165	        // 0.6 → trusted
166	        const state1 = applyOutcome({
167	            trust_score: 0.6 / 1.03,  // so after success → exactly 0.6
168	            consecutive_failures: 0, total_decisions: 0, correct_decisions: 0, trust_status: 'probation',
169	        }, true);
170	        expect(state1.trust_score).toBeCloseTo(0.6, 4);
171	        expect(state1.trust_status).toBe('trusted');
172	
173	        // Score in probation zone
174	        const state2: TrustState = {
175	            trust_score: 0.45,
176	            consecutive_failures: 0, total_decisions: 0, correct_decisions: 0, trust_status: 'probation',
177	        };
178	        const result2 = applyOutcome(state2, true);
179	        expect(result2.trust_status).toBe('probation');  // 0.45 * 1.03 = 0.4635 < 0.6
180	
181	        // 5 consecutive failures should always suspend regardless of score
182	        let state3: TrustState = {
183	            trust_score: 0.99,
184	            consecutive_failures: 4,
185	            total_decisions: 10, correct_decisions: 6, trust_status: 'trusted',
186	        };
187	        state3 = applyOutcome(state3, false);  // 5th consecutive failure
188	        expect(state3.consecutive_failures).toBe(5);
189	        expect(state3.trust_status).toBe('suspended');
190	    });
191	
192	    // ── Test 7: Post-reinstatement recovery path ──
193	    it('reinstated agent recovers from probation after enough successes', () => {
194	        // Start with reinstated values
195	        let state: TrustState = {
196	            trust_score: 0.4,
197	            consecutive_failures: 0,
198	            total_decisions: 50,
199	            correct_decisions: 30,
200	            trust_status: 'probation',
201	        };
202	
203	        // Need to reach 0.6 from 0.4: 0.4 * 1.03^n >= 0.6 → n >= ln(1.5)/ln(1.03) ≈ 13.7
204	        // Apply 14 successes
205	        for (let i = 0; i < 14; i++) {
206	            state = applyOutcome(state, true);
207	        }
208	
209	        const expectedScore = 0.4 * Math.pow(1.03, 14);
210	        expect(state.trust_score).toBeCloseTo(expectedScore, 4);
211	        expect(state.trust_score).toBeGreaterThanOrEqual(0.6);
212	        expect(state.trust_status).toBe('trusted');
213	        expect(state.consecutive_failures).toBe(0);
214	    });
215	});
