1	/**
2	 * Layerinfinite — Phase 6 Unit Tests: Pruning & Archival
3	 * ══════════════════════════════════════════════════════════════
4	 * Tests the data lifecycle rules: archive conditions,
5	 * cold-delete conditions, and salience stat computation.
6	 *
7	 * Run: npx vitest run tests/layer6/pruning.test.ts
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { describe, it, expect } from 'vitest';
12	
13	// ── Pruning rule constants (mirrors pruning-scheduler) ──
14	
15	const ARCHIVE_DAYS = 90;
16	const COLD_DELETE_DAYS = 365;
17	const SALIENCE_THRESHOLD = 0.01;
18	
19	// ── Helper: check if a row qualifies for archival ──
20	
21	interface OutcomeRow {
22	    id: string;
23	    created_at: string;
24	    salience: number;
25	    is_deleted: boolean;
26	    is_synthetic: boolean;
27	}
28	
29	interface ArchivedRow extends OutcomeRow {
30	    archived_at: string;
31	}
32	
33	function shouldArchive(row: OutcomeRow, referenceDate: Date): boolean {
34	    const rowDate = new Date(row.created_at);
35	    const ageDays = (referenceDate.getTime() - rowDate.getTime()) / (1000 * 60 * 60 * 24);
36	    return ageDays > ARCHIVE_DAYS && row.salience < SALIENCE_THRESHOLD && !row.is_deleted;
37	}
38	
39	function shouldColdDelete(archivedRow: ArchivedRow, referenceDate: Date): boolean {
40	    const archivedDate = new Date(archivedRow.archived_at);
41	    const daysSinceArchive = (referenceDate.getTime() - archivedDate.getTime()) / (1000 * 60 * 60 * 24);
42	    return daysSinceArchive > COLD_DELETE_DAYS;
43	}
44	
45	interface SalienceStats {
46	    avgSalience: number;
47	    minSalience: number;
48	    maxSalience: number;
49	    totalRows: number;
50	    belowThreshold: number;
51	}
52	
53	function computeSalienceStats(rows: OutcomeRow[]): SalienceStats {
54	    if (rows.length === 0) {
55	        return { avgSalience: 0, minSalience: 0, maxSalience: 0, totalRows: 0, belowThreshold: 0 };
56	    }
57	
58	    let sum = 0;
59	    let min = Infinity;
60	    let max = -Infinity;
61	    let belowThreshold = 0;
62	
63	    for (const row of rows) {
64	        sum += row.salience;
65	        if (row.salience < min) min = row.salience;
66	        if (row.salience > max) max = row.salience;
67	        if (row.salience < SALIENCE_THRESHOLD) belowThreshold += 1;
68	    }
69	
70	    return {
71	        avgSalience: sum / rows.length,
72	        minSalience: min,
73	        maxSalience: max,
74	        totalRows: rows.length,
75	        belowThreshold,
76	    };
77	}
78	
79	// ══════════════════════════════════════════════════════════════
80	// Tests
81	// ══════════════════════════════════════════════════════════════
82	
