138	
139	    // ── Test 5: Cold-delete after 365 days in archive ──
140	    it('cold-deletes archived rows older than 365 days', () => {
141	        const archived: ArchivedRow = {
142	            id: 'row-5',
143	            created_at: '2023-01-01T00:00:00Z',
144	            archived_at: '2024-01-01T00:00:00Z',  // ~530 days ago
145	            salience: 0.001,
