162	        };
163	
164	        expect(shouldColdDelete(recentArchive, now)).toBe(false);
165	    });
166	
167	    // ── Test 7: Salience stats computed correctly ──
168	    it('computes correct salience statistics', () => {
169	        const rows: OutcomeRow[] = [
170	            { id: 'a', created_at: '2025-01-01', salience: 0.001, is_deleted: false, is_synthetic: false },
