181	        expect(stats.maxSalience).toBe(0.5);
182	        expect(stats.avgSalience).toBeCloseTo((0.001 + 0.008 + 0.02 + 0.5 + 0.003) / 5, 6);
183	        // Below threshold (0.01): 0.001, 0.008, 0.003 → 3
184	        expect(stats.belowThreshold).toBe(3);
185	    });
186	
187	    // ── Test 8: Empty row set returns zeroed stats ──
188	    it('returns zeroed stats for empty row set', () => {
