47	function makeChain(
48	    terminalValue: { data: any; error?: any } = { data: null, error: null }
49	): any {
50	    const chain: any = Object.assign({}, {
51	        select: vi.fn(),
52	        eq: vi.fn(),
53	        upsert: vi.fn(),
54	        order: vi.fn(),
55	        limit: vi.fn(),
