62	    chain.select.mockReturnValue(chain);
63	    chain.eq.mockReturnValue(chain);
64	    chain.upsert.mockReturnValue(chain);
65	    chain.order.mockReturnValue(chain);
66	    chain.limit.mockReturnValue(chain);
67	    chain.gte.mockReturnValue(chain);
68	    // insert returns a nested chain (for insert().select().single())
69	    const insertChain: any = Object.assign({}, {
70	        select: vi.fn(),
71	    });
72	    const singleMock = vi.fn().mockResolvedValue({ data: { outcome_id: 'mock-id', timestamp: new Date().toISOString() }, error: null });
73	    insertChain.select.mockReturnValue({ single: singleMock });
74	    chain.insert.mockReturnValue(insertChain);
75	    return chain;
76	}
