15	
16	-- ────────────────────────────────────────────
17	-- TEST A1: log-outcome prerequisite — all FK targets exist
18	-- ────────────────────────────────────────────
19	DO $$
20	DECLARE v_count INT;
21	BEGIN
22	  SELECT COUNT(*) INTO v_count FROM dim_actions WHERE is_active = TRUE;
23	  IF v_count < 8 THEN
24	    RAISE EXCEPTION 'TEST A1 FAILED — Expected >= 8 active actions, found %', v_count;
25	  END IF;
26	  RAISE NOTICE 'TEST A1 PASSED — % active actions registered', v_count;
27	END $$;
