29	-- ────────────────────────────────────────────
30	-- TEST A2: hallucination prevention contract
31	-- A fake action_name CANNOT be in dim_actions
32	-- ────────────────────────────────────────────
33	DO $$
34	DECLARE v_count INT;
35	BEGIN
36	  SELECT COUNT(*) INTO v_count
37	  FROM dim_actions
38	  WHERE action_name = 'definitely_not_a_real_action_xyz';
39	
40	  IF v_count > 0 THEN
41	    RAISE EXCEPTION 'TEST A2 FAILED — Fake action found in registry!';
42	  END IF;
43	  RAISE NOTICE 'TEST A2 PASSED — Hallucination prevention: fake action correctly absent from registry';
44	END $$;
