46	-- ────────────────────────────────────────────
47	-- TEST A3: append-only constraint enforced at DB level
48	-- (the API relies on this trigger)
49	-- ────────────────────────────────────────────
50	DO $$
51	DECLARE
52	  v_outcome_id UUID;
53	  v_blocked    BOOLEAN := FALSE;
54	BEGIN
55	  -- Get an outcome to try updating
56	  SELECT outcome_id INTO v_outcome_id FROM fact_outcomes LIMIT 1;
57	
58	  IF v_outcome_id IS NULL THEN
59	    RAISE NOTICE 'TEST A3 SKIPPED — No outcomes in fact_outcomes yet';
60	    RETURN;
61	  END IF;
62	
63	  BEGIN
64	    UPDATE fact_outcomes SET success = NOT success WHERE outcome_id = v_outcome_id;
65	    RAISE EXCEPTION 'TEST A3 FAILED — UPDATE was NOT blocked by trigger!';
66	  EXCEPTION WHEN OTHERS THEN
67	    IF SQLERRM LIKE '%APPEND-ONLY%' THEN
