26	        } as any;
27	
28	        const score = computeCompositeScore(row);
29	
30	        // Prior pulls 0% success toward 50% when n=0
31	        // Expected Bayesian rate: (0 * 0 + 1) / (0 + 1 + 1) = 0.5
32	        // W_SUCCESS(0.4) * 0.5 + W_TREND(0.2) * 0.5 + W_SALIENCE(0.1) * 1.0 + W_RECENCY(0.1) * 0.5 = 0.45
33	        expect(score).toBeCloseTo(0.45, 1);
